INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('World History', '["The Eiffel Tower was originally intended to be built in Barcelona, Spain.","Honey never spoils; archaeologists have found edible honey in ancient Egyptian tombs.","The Great Wall of China is visible from space with the naked eye.","The shortest war in history lasted only 38 minutes (between Britain and Zanzibar in 1896).","A day on Venus is longer than a year on Venus."]', 2, 'Despite being a popular belief, the Great Wall is simply too narrow (about 15-30 feet wide) to be seen from space with the naked eye. NASA astronauts have confirmed it is not visible without aid.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Animals', '["Octopuses have three hearts and blue blood.","Goldfish have a memory span of only three seconds.","A group of flamingos is called a flamboyance.","Crows can recognize and remember human faces.","Sharks are older than trees — they have existed for over 450 million years."]', 1, 'Goldfish actually have a memory span of several months, not three seconds. They can be trained to navigate mazes and remember feeding schedules. The myth likely spread to excuse poor fish tank conditions.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Science', '["Hot water can freeze faster than cold water under certain conditions, a phenomenon known as the Mpemba effect.","There are more stars in the observable universe than grains of sand on all of Earth''s beaches.","Humans share about 60% of their DNA with bananas.","We only use 10% of our brains at any given time.","The speed of light in a vacuum is approximately 299,792 kilometers per second."]', 3, 'Brain imaging studies show we use virtually all of our brain, and most of it is active almost all the time. The myth may have originated from misquoted early neuroscience research.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Geography', '["Russia and the United States are separated by over 1,000 miles at their closest point.","Australia is wider than the Moon.","There are more public libraries in the United States than McDonald''s restaurants.","The Sahara Desert is not the largest desert on Earth — Antarctica is.","Canada has more lakes than all other countries combined."]', 0, 'At their closest point — between Big Diomede Island (Russia) and Little Diomede Island (USA) — the two countries are only about 2.4 miles apart. On a clear day you can see one from the other.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Human Body', '["The human stomach gets an entirely new lining every 3 to 4 days.","Your nose can detect over 1 trillion different scents.","Bones are about 5 times stronger than steel of the same density.","Humans lose most of their body heat through their head.","The human eye can distinguish about 10 million different colors."]', 3, 'Heat loss is proportional to the surface area exposed. Your head accounts for only about 10% of your body surface. This myth likely originated from old military studies where subjects wore insulated suits but not hats.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Food & Drink', '["Apples are more effective at waking you up in the morning than coffee.","Peanuts are not actually nuts — they are legumes.","Strawberries are not technically berries, but bananas are.","Eating carrots improves your eyesight beyond normal levels.","Cashews are always sold shelled because their shells contain a toxic substance related to poison ivy."]', 3, 'Carrots are rich in Vitamin A which helps maintain normal vision, but eating more carrots won''t improve eyesight beyond what''s normal. The myth was famously spread by British WWII propaganda to hide the invention of radar.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Space', '["A teaspoon of neutron star material would weigh about 10 million tons.","The Sun is a blue star.","Saturn''s rings are only about 30 feet thick on average despite being hundreds of thousands of miles wide.","There is a giant cloud of alcohol floating in space near the center of our galaxy.","Footprints left on the Moon by Apollo astronauts will likely last for millions of years."]', 1, 'The Sun is actually classified as a yellow dwarf star, though it emits white light. It appears yellow or orange from Earth due to atmospheric scattering. True blue stars are much hotter and larger than our Sun.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Language', '["The word \"set\" has the most definitions of any word in the English language.","The dot over the letters \"i\" and \"j\" is called a tittle.","The Eskimo language has over 100 words for snow.","There is a word for the fear of long words: hippopotomonstrosesquippedaliophobia.","The sentence \"The quick brown fox jumps over the lazy dog\" uses every letter of the English alphabet."]', 2, 'The "100 Eskimo words for snow" claim is a significant exaggeration. The Inuit and Yupik languages do have several snow-related terms, but so do many languages including English. The myth grew from a misreading of an early anthropological text.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Technology', '["The first computer bug was an actual bug — a moth found in a Harvard Mark II computer in 1947.","The QWERTY keyboard layout was originally designed to slow typists down to prevent typewriter jams.","More people in the world have access to a mobile phone than to a toilet.","The Nintendo Game Boy used less processing power than the Apollo 11 guidance computer.","The internet and the World Wide Web are the same thing."]', 4, 'The internet is the global network of connected computers, while the World Wide Web is just one service that runs on top of the internet. Email, FTP, and streaming are also internet services but not part of the Web.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Art & Music', '["Beethoven continued composing after becoming completely deaf.","The Mona Lisa has no eyebrows — it was fashionable to shave them off in Renaissance Florence.","The famous \"Starry Night\" by Van Gogh was painted from memory.","A violin is made from over 70 individual pieces of wood.","Vincent van Gogh only sold one painting during his lifetime."]', 2, 'Van Gogh painted "Starry Night" from the window of his room at the Saint-Paul-de-Mausole asylum in Saint-Rémy-de-Provence, not from memory. He described the view in several letters to his brother Theo.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Sports', '["The marathon distance of 26.2 miles was standardized from the original ancient Greek run.","Golf is the only sport to have been played on the Moon.","A regulation basketball court is exactly 94 feet long.","The Olympic Games were cancelled three times due to World War I and II.","Baseball was the first sport ever broadcast on radio."]', 0, 'The modern marathon distance was actually standardized at the 1908 London Olympics to accommodate the British royal family — the race was extended so it could start at Windsor Castle and finish in front of the royal box. The ancient Greek run was approximately 25 miles.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Animals', '["Wombats produce cube-shaped feces — the only known animal to do so.","A snail can sleep for up to three years.","Elephants are the only mammals that cannot jump.","Bats are blind.","Mantis shrimp can punch with the force of a bullet."]', 3, 'All bat species have functioning eyes. While many bats do use echolocation to navigate in the dark, they can also see — and some larger species like fruit bats rely primarily on sight. The phrase "blind as a bat" is simply false.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('History', '["Cleopatra lived closer in time to the Moon landing than to the construction of the Great Pyramid.","Vikings wore horned helmets.","Oxford University is older than the Aztec Empire.","Napoleon was not unusually short for his time — he was about 5''7\", average for a French man of his era.","The first President of the United States to appear on television was Franklin D. Roosevelt in 1939."]', 1, 'There is no historical evidence that Viking warriors wore horned helmets in battle. The image was popularized by 19th century Romanticism and theatrical costume design. Actual Viking helmets were simple rounded iron caps.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Science', '["Diamond is not the hardest natural material — lonsdaleite, a rare mineral, is theoretically harder.","Water expands when it freezes, which is why ice floats.","Lightning strikes the Earth about 100 times every second.","Lightning never strikes the same place twice.","The human brain generates about 20 watts of electrical power — enough to power a dim light bulb."]', 3, 'Lightning absolutely strikes the same place twice — in fact it frequently does. The Empire State Building is struck by lightning about 20 to 25 times per year. Tall structures are natural lightning rods precisely because they are struck repeatedly.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Pop Culture', '["The word \"robot\" was first used in a 1920 Czech play called R.U.R. by Karel Čapek.","Coca-Cola was originally green before the caramel coloring was added.","The hashtag symbol (#) is officially called an octothorpe.","Walt Disney was cryogenically frozen after his death.","Nintendo was founded in 1889 and originally made playing cards."]', 3, 'Walt Disney was cremated, not frozen. His death certificate and burial records confirm this. The cryonics rumor began circulating after his death in 1966 but has no factual basis. The first known case of cryonic preservation occurred one month after Disney died.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Human Body', '["Your blood vessels, if laid end to end, would stretch about 60,000 miles.","The human body contains enough carbon to make about 900 pencils.","Humans have five senses.","Fingernails grow about four times faster than toenails.","The strongest muscle in the human body relative to its size is the masseter — the jaw muscle."]', 2, 'Humans have far more than five senses. Beyond the classic sight, hearing, smell, taste, and touch, we also have proprioception (body position), thermoception (temperature), nociception (pain), equilibrioception (balance), and several others — totaling over 20 by most scientific counts.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Geography', '["The city of Istanbul spans two continents — Europe and Asia.","Vatican City is the smallest country in the world, at just 0.44 square kilometers.","The Amazon River discharges more freshwater into the ocean than the next seven largest rivers combined.","Africa is smaller than North America.","Montana, USA, has three times more cows than people."]', 3, 'Africa is actually significantly larger than North America. Africa covers about 30.3 million square kilometers, while North America covers about 24.7 million. Maps using the Mercator projection distort sizes near the poles, making North America appear larger than it actually is.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Animals', '["A group of pandas is called an embarrassment.","Sea otters hold hands while sleeping so they don''t drift apart.","Pigeons have been awarded military medals for bravery in both World Wars.","Ostriches bury their heads in the sand when frightened.","The tongue of a blue whale weighs as much as an elephant."]', 3, 'Ostriches do not bury their heads in the sand. When threatened they either run, kick, or lie flat against the ground with their neck outstretched. The myth may have originated from the fact that ostriches occasionally dig holes to tend to their eggs.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Food & Drink', '["MSG is harmful to human health.","Chocolate was once used as currency by the Aztecs.","The world''s most expensive coffee, Kopi Luwak, is made from beans passed through the digestive system of civets.","Almonds are members of the peach family.","The average American eats about 18 acres worth of pizza in their lifetime."]', 0, 'MSG (monosodium glutamate) has been extensively studied and found to be safe for the vast majority of people. The FDA classifies it as generally recognized as safe. The belief that it causes headaches stems from a debunked 1960s letter published in a medical journal, not scientific study.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Space', '["If you removed all the empty space from atoms in the human body, all of humanity would fit in a sugar cube.","The Sun accounts for 99.86% of the total mass of our solar system.","The Moon generates its own light.","One million Earths could fit inside the Sun.","There is a planet made almost entirely of diamond, called 55 Cancri e."]', 2, 'The Moon does not produce any light of its own. What we see as moonlight is actually reflected sunlight. The Moon''s surface reflects only about 12% of the sunlight that hits it — making it actually quite a poor reflector.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('History', '["Ancient Romans used crushed mouse brains as toothpaste.","The first coin ever minted was made in Lydia (modern-day Turkey) around 600 BC.","The Great Fire of London in 1666 destroyed 13,200 houses but killed fewer than 10 people.","Columbus was the first European to discover America.","The fax machine was invented before the telephone."]', 3, 'Norse explorer Leif Erikson reached North America around 1000 AD — nearly 500 years before Columbus. Archaeological evidence at L''Anse aux Meadows in Newfoundland confirms this. Columbus also never set foot on the North American mainland.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Science', '["Einstein failed math in school.","Glass is technically a supercooled liquid, not a solid.","The average person walks the equivalent of three times around the Earth in a lifetime.","Oxygen is actually a pale blue color in its liquid form.","A day on Mars is 24 hours and 37 minutes — very close to an Earth day."]', 0, 'Einstein excelled at mathematics from an early age. He mastered calculus by age 15. The myth likely originated from confusion over the Swiss grading system, which runs opposite to many others — his high scores were misread as failures.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Animals', '["Tardigrades (water bears) can survive in the vacuum of space.","A cat has 32 muscles in each ear.","Butterflies taste with their feet.","The mimic octopus can impersonate over 15 different species.","A dog''s mouth is cleaner than a human''s mouth."]', 4, 'Dogs'' mouths are not cleaner than humans''. Both contain hundreds of bacteria species, but they are largely different types. Dog mouths contain their own pathogens that can be harmful to humans. The comparison is essentially meaningless — they just have different bacteria.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Language', '["There is a language called Silbo Gomero that is entirely made up of whistles.","The language with the most native speakers is Mandarin Chinese.","\"Bookkeeper\" is the only common English word with three consecutive double letters.","English is the most spoken language in the world.","The word \"salary\" comes from the Latin word for salt, as Roman soldiers were sometimes paid in salt."]', 3, 'Mandarin Chinese has more native speakers than English. English has more total speakers when including second-language speakers, but in terms of native speakers, Mandarin leads significantly with over a billion speakers.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Technology', '["The first email was sent in 1971 by programmer Ray Tomlinson, who also chose the @ symbol.","Apple invented the touchscreen smartphone.","YouTube was originally designed as a video dating site.","The average person spends over 6 years of their life on social media.","There are more possible iterations of a game of chess than atoms in the known universe."]', 1, 'Touchscreen technology predates Apple by decades. The first touchscreen phone was the IBM Simon, released in 1994 — 13 years before the iPhone. Apple popularized and refined the technology but did not invent it.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Human Body', '["The surface area of a human lung is roughly the size of a tennis court.","Humans are the only animals that blush.","Your liver can regenerate itself completely if up to 75% is removed.","Humans and dinosaurs coexisted on Earth.","The acid in your stomach is strong enough to dissolve zinc."]', 3, 'Non-avian dinosaurs went extinct about 66 million years ago. The earliest human ancestors appeared only about 6-7 million years ago, and modern Homo sapiens roughly 300,000 years ago. The two groups missed each other by tens of millions of years.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Geography', '["Brazil is the only country in South America where Portuguese is the official language.","The Dead Sea is so salty that you can float effortlessly on its surface.","Mount Everest is the tallest mountain on Earth when measured from the Earth''s center.","Alaska is both the westernmost and easternmost state in the USA due to the Aleutian Islands crossing the 180th meridian.","The Nile flows northward — it is one of the few major rivers that flows toward the north."]', 2, 'When measured from the Earth''s center, Mount Chimborazo in Ecuador is actually the tallest mountain. Because the Earth bulges at the equator, Chimborazo''s peak — despite being lower in elevation above sea level — is farther from Earth''s center than Everest''s summit.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Animals', '["Dolphins sleep with one eye open and only half their brain at a time.","A group of crows is called a murder.","Camels store water in their humps.","Frogs cannot vomit — instead they eject their entire stomach and use their forearms to wipe it clean.","The horned lizard can shoot blood from its eyes as a defense mechanism."]', 2, 'Camel humps store fat, not water. The fat can be metabolized for energy during long journeys. Camels are able to survive without water through efficient kidneys and the ability to tolerate dehydration, not through stored water reserves.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Science', '["Sound travels about 4 times faster through water than through air.","The human body contains enough iron to make a small nail about 3 inches long.","Every atom in your body was forged inside a star.","It takes a photon up to 100,000 years to travel from the Sun''s core to its surface, but only 8 minutes to reach Earth.","The Great Barrier Reef is the largest living structure on Earth."]', 4, 'While the Great Barrier Reef is indeed enormous, it is actually the largest living structure visible from space. However, some scientists argue the Malpelo Fauna and Flora Sanctuary or other reef systems rival it. More commonly contested is the fact that fungi networks (like Armillaria) are larger single organisms.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Food & Drink', '["Honey is the only food that never expires — properly stored honey can last indefinitely.","Eating celery burns more calories than it contains.","The world''s most expensive spice by weight is saffron.","Avocados are technically a single-seeded berry.","A cucumber is 96% water — making it one of the most water-dense foods."]', 1, 'Celery does contain very few calories, but the idea that digesting it burns more than it provides is a myth. Digestion uses only a small fraction of the calories in food. Celery does have about 10 calories per stalk, and digestion uses far less than that.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('History', '["Ancient Greeks and Romans used urine as a teeth whitener and laundry detergent due to its ammonia content.","The Titanic had a swimming pool and a squash court on board.","Abraham Lincoln was a licensed bartender and co-owned a tavern.","Julius Caesar was an emperor of Rome.","The Hundred Years'' War between England and France actually lasted 116 years."]', 3, 'Julius Caesar was never emperor — he was a military general and dictator of the Roman Republic. The first true Roman Emperor was Augustus, Caesar''s adopted son. Caesar was assassinated in 44 BC before any formal empire was established.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Animals', '["Elephants are afraid of mice.","Penguins propose to their mates with a pebble.","A group of owls is called a parliament.","Crocodiles cannot stick out their tongues.","Polar bears have black skin under their white fur."]', 0, 'The idea that elephants fear mice is a persistent myth with no scientific basis. Studies and observations have shown elephants are largely indifferent to mice. The myth may date back to ancient Greece, where Pliny the Elder wrote about elephants fearing mice.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Space', '["The largest known star, UY Scuti, is so large that if it replaced our Sun, it would extend past the orbit of Jupiter.","Pluto is smaller than the United States in surface area.","The International Space Station travels at about 17,500 mph and orbits Earth every 90 minutes.","Space is completely silent because there is no air.","On Venus it rains sulfuric acid."]', 3, 'While it is true that sound cannot travel through the vacuum of space, space is not entirely silent in all senses. NASA has recorded pressure waves in gas clouds that, when converted to sound frequencies humans can hear, produce eerie sounds. Additionally, plasma waves create electromagnetic "sounds."');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Language', '["The word \"muscle\" comes from the Latin word for mouse, as flexing muscles look like mice moving under skin.","\"Dreamt\" is the only common English word that ends in \"mt.\"","The shortest complete sentence in English is \"Go.\"","The word \"quiz\" was invented as a bet by a Dublin theater owner.","French was the official language of England for about 300 years after the Norman Conquest in 1066."]', 3, 'The story that Richard Daly invented "quiz" on a bet in 1791 is a charming but almost certainly fabricated tale first published in 1836. The word "quiz" appears in print years before this alleged event, and no contemporary sources corroborate the story.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Science', '["There are more bacteria in your gut than cells in your entire body.","The Hawaiian Islands move about 2.5 inches closer to Japan every year.","Black holes suck everything in like a cosmic vacuum cleaner.","Helium was first discovered on the Sun before it was found on Earth.","The human eye is so sensitive it can detect a single photon of light in complete darkness."]', 2, 'Black holes do not actively pull things in. Their gravity follows the same inverse-square law as any massive object. If our Sun were replaced by a black hole of the same mass, Earth''s orbit would be completely unchanged. Objects only fall in if they venture within the event horizon.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Pop Culture', '["The film \"Psycho\" was the first American film to show a toilet flushing on screen.","The voice actor for Mickey Mouse, Walt Disney himself, had a fear of mice.","Monopoly was originally designed to teach people about the dangers of monopolistic landlords.","Frankenstein is the name of the monster in Mary Shelley''s novel.","Slinky was invented by accident when an engineer knocked a spring off his desk."]', 3, 'Frankenstein is the name of the scientist — Victor Frankenstein — not the creature. The monster is never named in the novel, referred to only as "the creature," "the demon," or "the wretch." This is one of literature''s most common misconceptions.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Human Body', '["Your teeth are the only part of your body that cannot repair themselves.","You cannot sneeze with your eyes open.","Humans are the only primates with chins.","The cornea is the only tissue in the human body with no blood supply — it gets oxygen directly from the air.","Humans have a vestigial muscle called the palmaris longus that some people lack entirely."]', 1, 'While it is very difficult to keep your eyes open during a sneeze due to a reflex, it is physically possible. The idea that your eyes would pop out is a myth — the pressure from a sneeze cannot disconnect your eyes from their optic nerves.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Animals', '["Hummingbirds are the only birds that can fly backwards.","A shrimp''s heart is located in its head.","The axolotl salamander can regrow its brain, heart, and limbs.","Sharks must keep swimming or they will die.","Rats laugh when tickled, producing ultrasonic chirps inaudible to humans."]', 3, 'While some shark species, like the great white, do need to swim to breathe through a process called ram ventilation, many sharks — including nurse sharks and wobbegongs — can pump water over their gills and rest motionless on the ocean floor.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Geography', '["The Pacific Ocean is larger than all of Earth''s landmasses combined.","Norway has a town called Å — the shortest place name in the world.","The Mariana Trench is deeper than Mount Everest is tall.","Egypt is the country with the most pyramids.","Greenland is the world''s largest island, but it is not a continent."]', 3, 'Sudan actually has more pyramids than Egypt. Sudan, the ancient land of Nubia, has between 200 and 255 known pyramids — roughly twice as many as Egypt. They are smaller and steeper, built by the ancient Kushite kingdoms.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Technology', '["The original name for Amazon was \"Cadabra\" and Google was \"Backrub.\"","The first domain name ever registered was Symbolics.com on March 15, 1985.","Computers speak in binary because it is the most efficient numbering system.","A GPS device works by receiving signals from at least 4 satellites simultaneously.","Wi-Fi does not stand for \"Wireless Fidelity\" — it is simply a brand name."]', 2, 'Computers use binary not because it is mathematically most efficient, but because electronic switches are most reliably represented in two states — on and off. Ternary (base-3) computing has been built and is theoretically more efficient, but the engineering challenges of three stable states made binary the practical standard.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('History', '["The first documented use of chemical warfare occurred during World War I.","Ancient Egyptians used moldy bread as an early form of antibiotic treatment.","The Colosseum in Rome could be flooded for mock naval battles.","Napoleon was actually taller than average for a French man of his era, standing about 5''7\".","The medieval period was entirely dark and devoid of scientific progress."]', 4, 'The "Dark Ages" narrative has been thoroughly debunked by historians. The medieval period saw the development of universities, advances in agriculture, significant architectural achievements, preservation and translation of classical texts, and major mathematical and astronomical progress, particularly in the Islamic world.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Food & Drink', '["Alcohol warms you up when you''re cold.","White chocolate is technically not chocolate — it contains no cocoa solids.","The fortune cookie was invented in the United States, not China.","Pistachios are technically a fruit — specifically a drupe (stone fruit).","The color of a chili pepper is not an indicator of how spicy it is."]', 0, 'Alcohol actually lowers your core body temperature. It causes blood vessels to dilate near the skin, creating a warm feeling — but this actually increases heat loss from your body. Drinking alcohol in cold weather can be dangerous precisely because it creates a false sense of warmth.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Science', '["Trees communicate with each other through underground fungal networks, sometimes called the \"Wood Wide Web.\"","We have mapped more of outer space than the ocean floor.","There are more trees on Earth than stars in the Milky Way galaxy.","The mantis shrimp can see 16 types of color receptors — humans have only 3.","A bolt of lightning is about 5 times hotter than the surface of the Sun."]', 1, 'We have actually mapped the ocean floor more completely than many parts of outer space in terms of surface detail. Over 80% of Earth''s oceans are unmapped at high resolution — but in terms of basic topographic mapping, we actually have better maps of ocean floors than many assume, derived from satellite gravity data.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Animals', '["Clownfish are all born male and the dominant fish in a group can change sex to female.","A group of jellyfish is called a smack.","The immortal jellyfish (Turritopsis dohrnii) can revert to its juvenile state after reaching adulthood, potentially living forever.","Chameleons change color to camouflage themselves.","Cows have best friends and show signs of stress when separated from them."]', 3, 'Chameleons primarily change color to communicate mood, temperature regulation, and social signals — not for camouflage. Their natural coloration is already well-suited to their environment. The color changes are largely about communication between chameleons.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Art & Music', '["The \"Happy Birthday\" song was under copyright until 2016.","Michelangelo was so secretive about his methods that he burned most of his drawings before he died.","The longest officially released song is \"The Rise and Fall of Bossanova\" at over 13 hours.","Rock and roll was invented by Elvis Presley.","Monet painted many of his most famous water lily works while nearly blind from cataracts."]', 3, 'Rock and roll evolved from a combination of African American musical traditions including blues, jazz, gospel, and rhythm and blues in the late 1940s and early 1950s. Artists like Chuck Berry, Little Richard, and Fats Domino were central to its creation. Elvis popularized it to white mainstream audiences but did not invent it.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Human Body', '["The human body has about 10 pints of blood, which makes up roughly 7-8% of total body weight.","You are about 1 centimeter taller in the morning than at night due to spinal compression.","Reading in dim light damages your eyesight.","Humans are the only animals known to shed emotional tears.","The total length of all the nerves in the human body is approximately 45 miles."]', 2, 'Reading in dim light causes eye strain and fatigue, but does not cause any permanent damage to your eyes. This widely believed parental caution has been thoroughly investigated by ophthalmologists who consistently find no evidence of lasting harm.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Space', '["Astronauts float in space because there is no gravity.","The Voyager 1 spacecraft, launched in 1977, is the most distant human-made object from Earth.","Jupiter''s Great Red Spot is a storm that has been raging for at least 350 years.","There are more moons in our solar system than planets — over 200 known moons.","The Moon is slowly drifting away from Earth at about 3.8 centimeters per year."]', 0, 'Astronauts float not because there is no gravity, but because they are in continuous free fall around the Earth. The ISS and its occupants are falling toward Earth while also moving fast enough sideways to keep missing it — this constant free fall creates the sensation of weightlessness. Gravity still very much exists in orbit.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('History', '["The first person convicted of speeding in a motor vehicle was going 8 mph in 1896.","Ancient Egyptians shaved off their eyebrows when their cats died as a sign of mourning.","The guillotine was still being used as an execution method in France as recently as 1977.","Paul Revere rode alone to warn colonists that \"the British are coming.\"","Abraham Lincoln was inducted into the Wrestling Hall of Fame in 1992."]', 3, 'Paul Revere did not ride alone — he was accompanied by William Dawes and later joined by Samuel Prescott. Revere was also captured before completing his ride. Additionally, he reportedly warned of the "Regulars," not "the British," since colonists considered themselves British at the time.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Animals', '["Ants can survive being microwaved because they are small enough to fit between the microwaves.","Lemmings commit mass suicide by jumping off cliffs.","A cockroach can live for several weeks without its head before dying of thirst.","Giraffes and humans have the same number of vertebrae in their necks — seven.","Honey badgers are immune to most venoms including cobra venom."]', 1, 'The lemming suicide myth was largely fabricated by a 1958 Disney documentary called "White Wilderness," which staged footage of lemmings being pushed off a cliff. In reality, lemmings do migrate in large groups but do not intentionally jump to their deaths.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Science', '["A single cloud can weigh more than 1 million pounds.","There are more possible shuffled orders of a deck of cards than there are atoms on Earth.","Ice is technically a mineral — it meets all the scientific criteria.","The tongue has no single \"taste map\" — the idea of distinct zones for sweet, salty, sour, and bitter is a myth.","Humans evolved from chimpanzees."]', 4, 'Humans did not evolve from chimpanzees. Rather, humans and chimpanzees share a common ancestor that lived roughly 6-7 million years ago. Both species evolved along separate branches from that common ancestor. This is one of the most common misunderstandings of evolutionary theory.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Geography', '["The shortest international border in the world is between Spain and Portugal''s Zamora province — just 120 meters.","Finland has more saunas than cars.","The Amazon Rainforest produces 20% of the world''s oxygen.","The city of Venice, Italy, is built on 118 small islands.","Wyoming and Colorado are the only rectangular states in the USA."]', 2, 'The Amazon does produce enormous amounts of oxygen, but it also consumes roughly the same amount through the decomposition of organic matter. The net oxygen contribution to the atmosphere is close to zero. Most of Earth''s atmospheric oxygen actually comes from marine phytoplankton.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Food & Drink', '["Vanilla flavoring was traditionally derived from beaver anal glands (castoreum).","The most nutritious part of a potato is just beneath the skin.","Champagne was invented by accident when bottles fermented unexpectedly.","You should drink 8 glasses of water per day.","The inside of a banana peel can soothe mosquito bites."]', 3, 'The "8 glasses a day" rule has no scientific basis. The amount of water a person needs varies dramatically based on body size, activity level, climate, and diet. Much of our water intake comes from food. The original 1945 recommendation was misread — it suggested 8 cups but noted most of that came from food.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Technology', '["Blu-ray is named because of the color of the disc.","The first computer mouse was made of wood.","The @ symbol is called \"arroba\" in Spanish and Portuguese and has been in use since the 15th century.","Spam email is named after a Monty Python sketch about Spam meat being unavoidable.","The first webcam was created to monitor a coffee pot at Cambridge University."]', 0, 'Blu-ray is named after the blue-violet laser used to read the disc, not the color of the disc itself. The discs are not noticeably blue. The "e" was intentionally dropped from "Blue" in the name because generic color terms cannot be trademarked.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Animals', '["Crows are known to leave gifts for humans who regularly feed them.","A snail''s shell is part of its body — it cannot survive without it.","The pistol shrimp can produce a cavitation bubble hotter than the surface of the Sun.","Bulls are enraged by the color red.","Koko the gorilla learned over 1,000 signs in American Sign Language."]', 3, 'Bulls (and all cattle) are actually colorblind to red. In bullfighting, the bull reacts to the movement of the matador''s cape, not its color. Studies have shown bulls charge equally at red, white, and blue capes. The red color is actually for the benefit of the human audience, to conceal bloodstains.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Science', '["Bananas are slightly radioactive due to their potassium-40 content.","Napoleon was exiled to Elba after his final defeat.","The total weight of all ants on Earth is comparable to the total weight of all humans.","Stomach acid is strong enough to dissolve stainless steel blades over time.","The Milky Way galaxy completes one rotation approximately every 225-250 million years."]', 1, 'Napoleon was exiled to the island of Elba after his first abdication in 1814 — but he escaped and returned to power. After his final defeat at Waterloo in 1815, he was exiled to the remote island of Saint Helena in the South Atlantic, where he died in 1821.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Pop Culture', '["The voice of Darth Vader (James Earl Jones) was not on set during filming — he dubbed the lines in post-production.","The word \"OK\" is the most recognized word in the world across languages.","Sherlock Holmes says \"Elementary, my dear Watson\" in Arthur Conan Doyle''s stories.","The Rubik''s Cube was invented by a Hungarian professor named Ernő Rubik to help explain three-dimensional geometry.","The first toy advertised on television was Mr. Potato Head in 1952."]', 2, 'The phrase "Elementary, my dear Watson" never appears in any of Arthur Conan Doyle''s original stories. Holmes does sometimes say "Elementary" and "my dear Watson" separately, but the iconic combined phrase was invented later in stage and film adaptations.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Human Body', '["The human body replaces approximately 330 billion cells per day.","Your body produces about 1 liter of saliva per day.","Hair and nails continue to grow after death.","Goosebumps are a vestigial reflex that once served to make our ancestors'' hair stand up to appear larger or keep warm.","The word \"muscle\" derives from the Latin \"musculus,\" meaning little mouse."]', 2, 'Hair and nails do not continue to grow after death. This illusion occurs because the skin dehydrates and retracts after death, making hair and nails appear longer. It is a post-mortem optical illusion, not actual growth, which requires living cells and a supply of glucose.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Animals', '["Wolves and dogs diverged from a common ancestor, and dogs were domesticated at least 15,000 years ago.","A group of ferrets is called a \"business.\"","Elephants are one of the few animals known to mourn their dead.","A porcupine can shoot its quills at predators.","Some species of jellyfish have no brain, no heart, and are 95% water."]', 3, 'Porcupines cannot shoot their quills. The quills are loosely attached and detach easily on contact with a predator, making it seem as if they were shot. The porcupine must make physical contact or swipe its tail to deploy quills effectively.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Geography', '["The tallest waterfall in the world is Niagara Falls.","The country of Lesotho is entirely surrounded by South Africa.","The Ganges River is considered one of the most polluted rivers in the world.","More than half of the world''s population lives within a 4,000-kilometer radius centered near Bangladesh.","The Atacama Desert in Chile is the driest non-polar desert on Earth."]', 0, 'Niagara Falls is famous for its volume but not its height. Angel Falls in Venezuela is the world''s tallest uninterrupted waterfall at 979 meters. Niagara Falls is only about 57 meters high. It ranks highly in terms of flow rate, which is what makes it so dramatic and powerful.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('History', '["The first recorded use of anesthesia in surgery was in ancient China, using a herbal mixture called mafeisan.","During World War II, the Nazis stole the Amber Room — a chamber decorated entirely in amber panels — and it has never been recovered.","The Eiffel Tower was supposed to be dismantled after 20 years but was saved because it worked as a radio antenna.","The Berlin Wall fell in 1991.","Ancient Romans numbered their centuries starting from the founding of Rome in 753 BC."]', 3, 'The Berlin Wall fell on November 9, 1989 — not 1991. The year 1991 is when the Soviet Union officially dissolved. The two events are related but distinct. The fall of the Wall was a pivotal moment in ending the Cold War, two years before the USSR''s collapse.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Science', '["The universe is approximately 13.8 billion years old.","Quantum entanglement allows particles to affect each other instantly regardless of distance.","Lobsters are biologically immortal — they do not age and keep growing indefinitely until they die of external causes.","Evolution is a theory with no supporting evidence.","There are more atoms in a grain of sand than grains of sand on all of Earth''s beaches."]', 3, 'Evolution is one of the most thoroughly supported theories in all of science, backed by evidence from paleontology, genetics, molecular biology, and direct observation. In science, "theory" does not mean guess — it means a well-tested explanation supported by extensive evidence. Calling it unsupported is simply factually incorrect.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Food & Drink', '["Ketchup was originally sold as a medicine in the 1830s to treat various ailments.","The Caesar salad was invented in Tijuana, Mexico, not Rome.","Orange the fruit was named before orange the color — the color is named after the fruit.","Turkey makes you sleepy because it contains high levels of tryptophan.","A pomato is a real hybrid plant that grows both potatoes underground and tomatoes above ground."]', 3, 'Turkey does contain tryptophan, but not in especially high amounts compared to chicken, beef, or cheese. The post-Thanksgiving sleepiness is far more likely caused by overeating, consuming alcohol, and a large carbohydrate intake — not turkey specifically. This myth resurfaces every Thanksgiving.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Animals', '["Owls can rotate their heads 360 degrees.","The blue-ringed octopus is one of the most venomous animals in the world — there is no antivenom.","Sloths are so slow that algae grows on their fur, providing camouflage.","Flamingos are not naturally pink — they are white, and turn pink from eating carotenoid-rich algae and crustaceans.","A horse can sleep both standing up and lying down."]', 0, 'Owls can rotate their heads about 270 degrees, not 360 — a full rotation. They achieve this impressive range through specially adapted neck vertebrae and blood vessel systems that prevent cutting off circulation. 270 degrees is still remarkable, but the full-circle claim is an exaggeration.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Technology', '["The first photograph ever taken required an 8-hour exposure.","Video games have been shown in studies to improve hand-eye coordination and problem-solving skills.","The USB symbol is based on Neptune''s trident.","The iPhone was the first smartphone ever created.","Before GPS, ships used a method called dead reckoning to estimate their position."]', 3, 'The IBM Simon, released in 1994, is widely considered the first smartphone. It had touchscreen technology, email, calendar, and apps — 13 years before the iPhone launched in 2007. The iPhone was transformative but definitely not the first.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Human Body', '["Your body has more sweat glands than hairs on your head — about 4 million.","The appendix is now believed to serve a purpose — it may function as a reservoir for beneficial gut bacteria.","Humans have a diving reflex that slows the heart rate when the face is submerged in cold water.","You lose most of your body''s heat through your feet.","The small intestine is actually longer than the large intestine — about 6 meters versus 1.5 meters."]', 3, 'Heat loss is proportional to surface area exposed. Feet are not disproportionate heat losers unless they are exposed to cold. This myth, like the head version, stems from the same flawed military studies and has been refuted by thermographic imaging research.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('History', '["The Great Pyramid of Giza was the tallest man-made structure in the world for over 3,800 years.","Abraham Lincoln''s Emancipation Proclamation did not actually free all enslaved people immediately — it only applied to Confederate states.","The Pilgrims landed at Plymouth Rock in 1620.","The first successful powered airplane flight by the Wright Brothers lasted only 12 seconds.","Genghis Khan''s empire was the largest contiguous land empire in history."]', 2, 'The Pilgrims first landed at Provincetown, at the tip of Cape Cod, in November 1620. They explored the area for several weeks before choosing Plymouth as their settlement site in December. Plymouth Rock as a specific landing point is also considered largely symbolic — it was not identified as the landing spot until over a century later.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Science', '["The weight of the internet — all the electrons moving through it — is estimated to be about 50 grams.","Leeches were still used in modern medicine as recently as 2004 and are FDA-approved medical devices.","The chances of a shuffled deck of cards being in the same order as any previous shuffle are essentially zero.","Antibiotics are effective against viral infections like the flu.","Sound cannot travel through a vacuum — there must be matter for sound waves to propagate."]', 3, 'Antibiotics target bacteria and are completely ineffective against viruses. The flu is caused by influenza viruses, and taking antibiotics for it does nothing — while contributing to antibiotic resistance. This misunderstanding has led to a global public health crisis of antibiotic-resistant bacteria.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Pop Culture', '["The Simpsons has predicted numerous real-world events years before they happened.","The LEGO Group is the world''s largest tire manufacturer by number of tires produced.","Winnie-the-Pooh was inspired by a real bear named Winnie who lived at the London Zoo.","James Bond''s famous line \"shaken, not stirred\" appears in the very first Bond film.","The checkerboard pattern on a Vans shoe was inspired by the floor of a California pizza restaurant."]', 3, 'In the first Bond film, "Dr. No" (1962), Bond actually orders his drink stirred, not shaken. The iconic "shaken, not stirred" phrase became a defining Bond characteristic in later films and became so associated with the character that the original deviation is now largely forgotten.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Animals', '["Lobsters were once so abundant in colonial America that they were considered \"poverty food\" and fed to prisoners.","Piranhas are deadly man-eating fish that regularly attack and kill humans.","An octopus has three hearts, nine brains (one central and eight in its arms), and blue blood.","The dragonfly is one of the most efficient hunters in the animal kingdom, with a 95% kill rate.","Cats are the only domestic animals that were never truly domesticated — they domesticated themselves."]', 1, 'Piranha attacks on humans are extremely rare. Piranhas are largely scavengers and rarely attack living prey larger than themselves unless in unusual circumstances such as drought concentrating them in small pools. Theodore Roosevelt''s famous piranha encounter in 1914 was staged by locals who had pre-starved the fish.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Geography', '["The Ural Mountains in Russia form the traditional geographic boundary between Europe and Asia.","The country with the most time zones is France, with 12, due to its overseas territories.","Iceland is green and Greenland is icy — the names are historically swapped to mislead settlers and raiders.","The Caspian Sea is the world''s largest landlocked body of water.","The Bermuda Triangle has an unusually high number of ship and plane disappearances."]', 4, 'Statistical analyses have consistently shown that the Bermuda Triangle does not have a higher rate of disappearances than other heavily traveled ocean regions. Lloyd''s of London does not charge higher insurance rates for ships passing through it. The mystery was largely invented and perpetuated by books and media in the 1970s.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Food & Drink', '["The smell of fresh bread is so psychologically comforting that real estate agents bake bread before open houses.","Twinkies do not last forever — their actual shelf life is about 45 days.","Eating late at night causes weight gain because your metabolism slows while you sleep.","The sandwich was named after the 4th Earl of Sandwich, who reportedly ate meat between bread to avoid leaving the card table.","Lobster was once so cheap it was used as fertilizer and fish bait in Massachusetts."]', 2, 'Weight gain is determined by total caloric intake versus expenditure — not the timing of when calories are consumed. The body does not gain weight simply from eating late. What matters is total daily calories. The myth persists because late-night eating often involves high-calorie snacks, not because of the time itself.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Technology', '["The original Star Wars special effects were created without CGI — almost everything was a physical model or costume.","The barcode was inspired by Morse code — the inventor extended dots and dashes into thin and thick lines.","A standard piano has 88 keys, but Bösendorfer makes a model with 97.","The microwave was invented by a scientist intentionally trying to cook food with radiation.","YouTube uses more bandwidth per day than the entire internet did in 2000."]', 3, 'The microwave oven was invented by accident. Percy Spencer, an engineer working on radar technology at Raytheon, noticed that a candy bar in his pocket melted when he stood near a magnetron. He then intentionally experimented with food and patented the microwave cooking process in 1945.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('History', '["The first country to give women the right to vote was the United States.","Thomas Edison did not invent the lightbulb — he improved on designs already in existence.","The printing press was invented by Johannes Gutenberg around 1440 and is considered one of the most important inventions in history.","The word \"salary\" derives from the Latin \"salarium,\" related to salt payments to Roman soldiers.","Mahatma Gandhi was nominated for the Nobel Peace Prize five times but never won."]', 0, 'New Zealand was the first self-governing country to grant women the right to vote in 1893, followed by Australia in 1902. The United States did not grant women nationwide voting rights until 1920 with the 19th Amendment — 27 years after New Zealand.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Animals', '["A group of cats is called a clowder.","Elephants can communicate through seismic vibrations felt through their feet across distances of several miles.","The bombardier beetle can fire boiling hot chemicals from its rear end at over 100 pulses per second.","Koalas are bears.","Seahorses are monogamous and the male carries and gives birth to the young."]', 3, 'Koalas are marsupials, not bears. They are more closely related to wombats and kangaroos than to any bear species. The misnomer "koala bear" likely arose from their teddy-bear-like appearance and has persisted despite being zoologically incorrect for over a century.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Science', '["At absolute zero, all molecular motion ceases completely.","The speed of sound is approximately 1,235 km/h (767 mph) in air at sea level.","The tongue is the strongest muscle in the human body.","Quantum computers can theoretically solve certain problems in seconds that would take classical computers millions of years.","The human appendix may play a role in maintaining healthy gut flora during illness."]', 2, 'The tongue is not the strongest muscle — this is a matter of how "strongest" is defined. The masseter (jaw muscle) exerts the most force, the heart does the most total work, and the gluteus maximus is the largest muscle. The tongue is not a leading contender by any common measure of strength.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Pop Culture', '["The word \"nerd\" was first used in Dr. Seuss''s 1950 book \"If I Ran the Zoo.\"","\"Beam me up, Scotty\" is a direct quote from Star Trek.","The Tetris theme song is a Russian folk song called \"Korobeiniki.\"","James Cameron''s \"Titanic\" cost more to produce than the actual Titanic ship.","The iconic \"I Am Your Father\" line from Star Wars was kept secret even from the cast."]', 1, 'The exact phrase "Beam me up, Scotty" was never actually spoken in any Star Trek television series or film. The closest that was said was "Beam me up, Mr. Scott" and variations thereof. It is one of the most famous misquotes in popular culture.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Human Body', '["Humans are bioluminescent — we emit a faint glow that is too weak for the naked eye to see.","The human brain is about 73% water.","You have a second brain in your gut — the enteric nervous system contains about 100 million nerve cells.","Blood is blue inside your body and turns red when exposed to oxygen.","Identical twins do not have identical fingerprints."]', 3, 'Human blood is always red — it is never blue inside the body. Deoxygenated blood is a dark red, while oxygenated blood is bright red. Veins appear blue through the skin because of how different wavelengths of light penetrate tissue and are reflected back. This is a very common misconception, often reinforced in school diagrams.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Geography', '["The equator passes through the middle of Africa.","The Sahara Desert was a lush, green savanna with hippos and crocodiles just 10,000 years ago.","Japan has more than 6,800 islands.","The Danube River flows through more countries than any other river in the world — 10 countries.","Texas is larger than France."]', 0, 'The equator does pass through Africa, but not through the middle. It runs through the northern portion of the continent, passing through countries like Gabon, Republic of Congo, Uganda, Kenya, and Somalia. Much of Africa — including South Africa, Zimbabwe, and most of the Sahara — lies well outside the equatorial zone.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Animals', '["Dogs have about 300 million olfactory receptors in their noses, compared to about 6 million in humans.","The Greenland shark can live for over 400 years, making it the longest-lived vertebrate known.","Cows produce more milk when they listen to calming music.","Zebra stripes are unique to each individual, like human fingerprints.","Ravens are among the smartest animals — they have been observed planning for the future and engaging in deception."]', 3, 'While zebra stripe patterns are indeed individual and can be used to distinguish between animals, they are not precisely analogous to fingerprints. The comparison is often made loosely but the uniqueness of zebra stripes is a matter of degree and complexity rather than the highly precise individual identification that fingerprints provide.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('History', '["The construction of the Eiffel Tower was completed in just two years, two months, and five days.","Nikola Tesla and Thomas Edison had a famous feud known as the \"War of Currents.\"","Ancient Greeks had a word, \"apanthropy,\" for the desire to avoid human society — the origin of the word \"misanthrope.\"","George Washington had wooden teeth.","The Mongol Empire, at its peak, covered about 24 million square kilometers."]', 3, 'George Washington''s dentures were not made of wood. His four sets of dentures were made from ivory (from hippos and elephants), human teeth, animal teeth, and metal alloys. The wooden teeth myth may have originated from the grain-like staining of ivory over time, which can resemble wood texture in portraits.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Science', '["The human genome contains roughly 3 billion base pairs of DNA.","Pluto was downgraded from a planet to a \"dwarf planet\" in 2006 by the International Astronomical Union.","The chemical symbol for gold (Au) comes from the Latin word \"aurum.\"","Supernovas can briefly outshine entire galaxies containing hundreds of billions of stars.","The sun rises in the east and sets in the west everywhere on Earth."]', 4, 'While the general principle is correct, at the poles and during solstices it breaks down significantly. At the North or South Pole, the sun does not rise or set in the traditional east/west sense — it circles the horizon. During the midnight sun season, the sun never truly sets.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Food & Drink', '["The world''s oldest known recipe is for beer, found on a Sumerian clay tablet from around 1800 BC.","Durian fruit is so pungent it is banned on the Singapore subway system.","Sushi is all raw fish.","The tomato was thought to be poisonous by many Europeans when it first arrived from the Americas.","Nutmeg is psychoactive in large doses and was used historically as a hallucinogen."]', 2, 'Sushi refers to vinegared rice, not raw fish. Many types of sushi contain no fish at all — including vegetable sushi, egg (tamago), and cooked seafood varieties. Raw fish served alone is called sashimi. The conflation of sushi with raw fish is a widespread but inaccurate Western misconception.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Technology', '["The average smartphone today has more computing power than all of NASA''s computers combined during the Apollo moon landings.","CAPTCHA stands for \"Completely Automated Public Turing test to tell Computers and Humans Apart.\"","The first programming language was written by Ada Lovelace in the 1840s for Charles Babbage''s Analytical Engine.","The internet was invented by Al Gore.","The most expensive domain name ever sold was Voice.com, for $30 million in 2019."]', 3, 'The internet was developed by researchers including Vint Cerf and Bob Kahn, who created the TCP/IP protocols in the 1970s. It grew from ARPANET, a US Department of Defense project. Al Gore did champion legislation funding the expansion of the internet as a senator, but he never claimed to have invented it — that was a media mischaracterization of his actual quote.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Animals', '["Cats always land on their feet.","The blue whale is the largest animal known to have ever existed on Earth.","Pigeons can recognize their own reflections in a mirror — one of few non-human species to pass the mirror test.","There are about 10 quintillion (10,000,000,000,000,000,000) individual insects on Earth.","Moths are not actually attracted to light — they are confused by it, mistaking artificial light for the moon."]', 0, 'While cats have a remarkable righting reflex that allows them to orient themselves during a fall, they do not always land on their feet. Falls from very short distances do not give them enough time to right themselves, and falls from great heights can cause serious injury. Many cats are injured in falls every year.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Human Body', '["Your eyes see everything upside down, and your brain flips the image.","The human nose can remember up to 50,000 different scents.","Humans are the only animals known to have a true language with grammar and syntax.","Humans only use 10% of their DNA — the rest is \"junk DNA.\"","Your heart beats about 100,000 times per day."]', 3, 'Research has shown that the vast majority of the human genome serves some regulatory or structural function. The ENCODE project determined that about 80% of the genome is biochemically active. The "junk DNA" label, once common in genetics, has largely been abandoned as scientists have discovered extensive functions for previously dismissed sequences.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('History', '["The Great Wall of China took over 2,000 years to build, with major construction in different dynasties.","Winston Churchill was half American — his mother, Jennie Jerome, was born in Brooklyn.","Ancient Egyptians had a form of bowling that dates back over 5,000 years.","The Spanish Inquisition was the most deadly inquisition in history.","The word \"alphabet\" comes from the first two letters of the Greek alphabet: alpha and beta."]', 3, 'The Spanish Inquisition, while notorious, was actually responsible for far fewer deaths than its popular reputation suggests. Modern historians estimate around 3,000-5,000 executions over 350 years. Contemporary religious persecutions in Northern Europe, such as witch trials, claimed proportionally more lives. The Monty Python sketch massively inflated its fearsome reputation.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Space', '["The James Webb Space Telescope can detect the heat signature of a bumblebee from the distance of the Moon.","Mars has the tallest volcano in the solar system — Olympus Mons is nearly three times taller than Everest.","The Big Bang was a massive explosion in space.","Light from the Sun takes about 8 minutes and 20 seconds to reach Earth.","There may be more stars in the universe than grains of sand on all of Earth''s beaches."]', 2, 'The Big Bang was not an explosion in space — it was an expansion of space itself. There was no "before," no center of the explosion, and no space to explode into. The term "Big Bang" is somewhat misleading; it was coined sarcastically by astronomer Fred Hoyle who rejected the theory. It was more like the sudden beginning of everything, including time.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Science', '["Whales evolved from land mammals and their ancestors walked on four legs.","We have discovered and named all the elements that can possibly exist.","The element mercury is liquid at room temperature.","Sleeping less than 6 hours per night is associated with a significantly higher risk of heart disease.","The chemical formula for table sugar (sucrose) is C12H22O11."]', 1, 'While all elements up to oganesson (118) have been synthesized or discovered, theoretical physics suggests that heavier elements may be possible. The "Island of Stability" hypothesis predicts that superheavy elements around atomic number 126 could have longer half-lives than currently known superheavy elements, though they have not yet been created.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Animals', '["The fastest animal on Earth is the peregrine falcon, reaching speeds over 240 mph in a dive.","Ants have been farming fungi and aphids for millions of years longer than humans have been farming.","The axolotl''s ability to regenerate is being studied for potential applications in human medicine.","Male seahorses experience actual pregnancy — the fertilized eggs develop inside a pouch on the male.","A group of fish is called a school because they \"school\" each other about predators."]', 4, 'The word "school" when referring to fish actually comes from the Dutch word "schole," meaning a troop or crowd. It has no connection to the English word "school" meaning educational institution — they are simply homophones with entirely different etymological origins.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Art & Music', '["The famous \"Blue Period\" in Picasso''s work was triggered by the suicide of his close friend.","Beethoven''s Ninth Symphony was composed first among his nine symphonies.","The Sistine Chapel ceiling took Michelangelo four years to paint (1508-1512).","Jazz musician Charlie Parker could play 16th notes at tempos above 300 beats per minute.","The Louvre in Paris is the most visited art museum in the world."]', 1, 'Beethoven composed his symphonies in numerical order — his Ninth Symphony was his last, composed in 1824 when he was almost completely deaf. It was a groundbreaking work, the first major symphony to incorporate a full choir and vocal soloists, and it premiered to great acclaim despite Beethoven being unable to hear the applause.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Geography', '["The country of Bolivia has two capital cities — Sucre (constitutional) and La Paz (seat of government).","The Dead Sea is shrinking at a rate of about 1 meter per year.","The Gobi Desert spans both China and Mongolia and is the largest desert in Asia.","The Amazon River is the longest river in the world.","New Zealand was the last major landmass to be settled by humans — Māori arrived around 1280 AD."]', 3, 'The Nile River is traditionally considered the longest river in the world at approximately 6,650 km, compared to the Amazon at about 6,400 km. However, this is genuinely contested — a 2007 study suggested the Amazon might be longer depending on how its source is defined. The Amazon carries by far the most water of any river.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Food & Drink', '["Wasabi served in most sushi restaurants outside Japan is not real wasabi — it is colored horseradish.","The ice cream cone was reportedly invented at the 1904 St. Louis World''s Fair.","Chili peppers are technically fruits from a botanical perspective.","Coca-Cola was invented by a pharmacist named John Pemberton as a patent medicine in 1886.","Coffee is made from coffee beans."]', 4, 'Technically, coffee is made from coffee seeds, not beans. The coffee "bean" is the seed found inside the coffee cherry fruit. The term "bean" is used colloquially because of the seed''s resemblance to legume beans, but botanically they are seeds of a fruit, not beans at all.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Science', '["Space is cold — the temperature of space is approximately -270°C.","The color of the sky is blue because of Rayleigh scattering of sunlight by the atmosphere.","Water is the only common substance on Earth that is less dense as a solid than as a liquid.","The average distance from Earth to the Moon is about 384,400 kilometers.","A year on Mercury is only 88 Earth days long."]', 0, 'Space itself does not have a "temperature" in the conventional sense because temperature requires matter. The cosmic microwave background radiation corresponds to about -270°C, but an astronaut in direct sunlight could actually overheat. Objects in space can be extremely hot or cold depending on radiation exposure, not because "space" has a temperature.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Pop Culture', '["The @ symbol was once almost removed from computer keyboards before email saved its relevance.","The board game Scrabble was invented during the Great Depression by an unemployed architect.","Stan Lee appeared in cameo roles in almost every Marvel film until his death in 2018.","Monopoly was invented by Charles Darrow during the Great Depression as a way to get rich.","The first novel ever written on a typewriter was Mark Twain''s \"The Adventures of Tom Sawyer.\""]', 3, 'Monopoly was actually invented by Elizabeth Magie in 1903, originally called "The Landlord''s Game." She designed it to teach about the negative effects of land monopolies. Charles Darrow adapted her game decades later and sold it to Parker Brothers — receiving all the credit and royalties while Magie received almost nothing.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('Animals', '["The platypus is one of the few venomous mammals — males have a spur on their hind legs that delivers venom.","Wolves howl not to communicate with the moon, but to communicate with other wolves over long distances.","Crocodilians are more closely related to lizards than to birds.","The Greenland shark grows only about 1 cm per year and reaches sexual maturity at about 150 years old.","Dolphins have names for each other — unique signature whistles used to identify individuals."]', 2, 'Crocodilians (crocodiles, alligators, caimans) are actually more closely related to birds than to lizards. Both crocodilians and birds are archosaurs, sharing a common ancestor. Lizards belong to the lepidosaur lineage which branched off much earlier. This makes the crocodile one of the bird''s closest living relatives.');
INSERT INTO puzzles (category, statements, fib_index, fib_explanation) VALUES ('World Records & Extremes', '["The loudest sound ever recorded was the 1883 eruption of Krakatoa, heard 4,800 km away.","The hottest temperature ever recorded on Earth''s surface was 56.7°C in Death Valley in 1913.","The human voice can shatter glass.","The deepest point on Earth, the Mariana Trench, is about 11 kilometers below the ocean surface.","The longest recorded flight of a chicken is 13 seconds."]', 2, 'While it is theoretically possible for a very precisely tuned and amplified voice to shatter a thin crystal glass at its exact resonant frequency, an unaided human voice cannot do this. The glass-shattering trick performed by singers in demonstrations always uses electronic amplification — sometimes concealed. An unaided human voice simply does not generate enough sound pressure.');
INSERT INTO puzzles (special_date, category, statements, fib_index, fib_explanation) VALUES ('2027-03-28', 'Easter Traditions', '["Easter eggs are dyed and hidden as part of the Easter Bunny tradition dating back to ancient times.","The Easter Bunny is believed to have origins in pagan spring festivals.","Hot cross buns are traditionally eaten on Good Friday before Easter Sunday.","The word Easter comes from Eostre, an ancient Germanic goddess of spring.","Easter is always celebrated on a Sunday between March 22 and April 25."]', 0, 'While Easter egg hunts and the Easter Bunny are popular modern traditions, they do not date back to ancient times. The Easter Bunny tradition actually originated in 16th-century Germany and was brought to America by German immigrants in the 1700s. Easter eggs themselves became associated with the holiday much later through Christian symbolism (resurrection), and the practice of dyeing and hunting them is a relatively modern tradition that developed over centuries, not an ancient custom.');
INSERT INTO puzzles (special_date, category, statements, fib_index, fib_explanation) VALUES ('2026-12-25', 'Christmas Traditions', '["Christmas trees were first popularized in America by Prince Albert and Queen Victoria of England in the 1840s.","Rudolph the Red-Nosed Reindeer was created by the Montgomery Ward department store in 1939.","The tradition of hanging stockings comes from Saint Nicholas dropping gold coins down a chimney.","Candy canes were originally white and only became red and white striped in the 1600s.","Santa Claus is based on Saint Nicholas, a real bishop from Turkey."]', 3, 'Candy canes were actually created as red and white striped sweets much later than the 1600s. The original candy canes from the 17th century were plain white and straight. The red stripes and curved shape we know today were not standardized until the 1800s, with commercial production of red and white striped candy canes beginning in the late 1800s and early 1900s.');
INSERT INTO puzzles (special_date, category, statements, fib_index, fib_explanation) VALUES ('2026-11-26', 'Thanksgiving History', '["Thanksgiving became a national holiday in America in 1863 when President Abraham Lincoln proclaimed it.","The first Thanksgiving feast in 1621 was celebrated by Pilgrims and Native Americans.","Turkey was likely served at the first Thanksgiving celebration in 1621.","Thanksgiving is celebrated on the fourth Thursday of November.","The Pilgrims traveled on a ship called the Mayflower."]', 2, 'While turkey is now the traditional Thanksgiving bird, there is no historical evidence that turkey was actually served at the first Thanksgiving in 1621. Contemporary accounts and historical records suggest the feast likely included wildfowl such as ducks and geese, as well as deer, but turkey was not documented as part of that meal. Turkey became associated with Thanksgiving celebrations much later, over centuries, and is now the dominant tradition.');
INSERT INTO puzzles (special_date, category, statements, fib_index, fib_explanation) VALUES ('2026-11-11', 'Veterans Day Facts', '["Veterans Day is celebrated on November 11th each year.","Veterans Day commemorates the end of World War I, which occurred on November 11, 1918.","Originally called Armistice Day, the holiday was renamed Veterans Day in 1978.","Veterans Day honors all military veterans, while Memorial Day honors those who died in service.","The United States is the only country that celebrates Veterans Day on November 11th."]', 4, 'Many countries around the world celebrate November 11th as a day honoring military veterans and the end of World War I, including Canada (Remembrance Day), France, Germany, Australia, and numerous other nations. It is not unique to the United States. The date November 11 holds international significance because it marks the armistice that ended World War I in 1918.');